import React from "react";
import { Card, CardDeck } from "react-bootstrap";
import { getEducationHistory } from "../../utilities";

export const Education = () => {
  const history = getEducationHistory();
  return (
    <Card>
      <Card.Header>Education</Card.Header>
      <Card.Body>
        <CardDeck>
          {history.map((item, index) => (
            <Card key={`ed-${index}`}>
              <Card.Body>
                <p>{item.completionDate}</p>
                <h3>{item.programName}</h3>
                <p>
                  {item.institutionName} - {item.location}
                </p>

              </Card.Body>
            </Card>
          ))}
        </CardDeck>
      </Card.Body>
    </Card>
  );
};
